import { Router } from "express";
import { activeBranchMiddleware } from "../../middlewares/activeBranch.js";
import { authMiddleware } from "../../middlewares/auth.js";
import { requireRoles } from "../../middlewares/roles.js";
import { categoriesController } from "./categories.controller.js";
export const categoriesRouter = Router();
categoriesRouter.use(authMiddleware, requireRoles(["OWNER"]), activeBranchMiddleware);
categoriesRouter.get("/", (req, res) => categoriesController.list(req, res));
categoriesRouter.get("/:categoryId", (req, res) => categoriesController.getById(req, res));
categoriesRouter.post("/", (req, res) => categoriesController.create(req, res));
categoriesRouter.patch("/:categoryId", (req, res) => categoriesController.update(req, res));
categoriesRouter.delete("/:categoryId", (req, res) => categoriesController.remove(req, res));
